// Format error for Slack with retry tracking
const input = $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Initialize retry tracking
if (!staticData.errorRetries) {
  staticData.errorRetries = {};
}

const workflowName = input.workflow?.name || input.workflowName || 'Unknown Workflow';
const workflowId = input.workflow?.id || input.workflowId || 'unknown';
const executionId = input.execution?.id || input.executionId || 'unknown';
const nodeName = input.node?.name || input.nodeName || 'Unknown Node';
const errorMessage = input.error?.message || input.errorMessage || input.message || 'Unknown error';
const errorStack = input.error?.stack || input.errorStack || '';
const timestamp = new Date().toISOString();

// Create unique error key for deduplication
const errorKey = `${workflowId}:${nodeName}:${errorMessage.substring(0, 50)}`;

// Track retry attempts
const retryInfo = staticData.errorRetries[errorKey] || { count: 0, firstSeen: timestamp };
retryInfo.count++;
retryInfo.lastSeen = timestamp;
staticData.errorRetries[errorKey] = retryInfo;

// Clean old error tracking (older than 1 hour)
const now = Date.now();
Object.keys(staticData.errorRetries).forEach(key => {
  const info = staticData.errorRetries[key];
  if (now - new Date(info.lastSeen).getTime() > 60 * 60 * 1000) {
    delete staticData.errorRetries[key];
  }
});

// Truncate stack trace
const stackPreview = errorStack.length > 500 
  ? errorStack.substring(0, 500) + '...' 
  : errorStack;

// Build Slack blocks
const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: ':rotating_light: Workflow Error', emoji: true }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Workflow:*\n${workflowName}` },
      { type: 'mrkdwn', text: `*Failed Node:*\n${nodeName}` }
    ]
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Error:*\n\`\`\`${errorMessage}\`\`\`` }
  }
];

if (stackPreview) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*Stack:*\n\`\`\`${stackPreview}\`\`\`` }
  });
}

blocks.push(
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*Execution:*\n\`${executionId}\`` },
      { type: 'mrkdwn', text: `*Occurrences:*\n${retryInfo.count} time(s)` }
    ]
  },
  {
    type: 'context',
    elements: [{ type: 'mrkdwn', text: `Error at ${new Date(timestamp).toLocaleString('en-US', { timeZone: 'America/Denver' })}` }]
  },
  {
    type: 'actions',
    elements: [
      {
        type: 'button',
        text: { type: 'plain_text', text: 'View in n8n', emoji: true },
        url: `https://hwc.ocelot-wahoo.ts.net:2443/workflow/${workflowId}/executions/${executionId}`,
        action_id: 'view_execution'
      }
    ]
  }
);

return {
  json: {
    channel: '#hwc-alerts',
    text: `:rotating_light: Workflow Error: ${workflowName} - ${errorMessage.substring(0, 100)}`,
    blocks,
    errorKey,
    retryCount: retryInfo.count,
    workflowId,
    executionId
  }
};

// Check if Slack failed, use ntfy as fallback
const input = $input.first().json;

if (input.error) {
  return {
    json: {
      useFallback: true,
      ntfyMessage: {
        topic: 'hwc-alerts',
        title: 'n8n Workflow Error (Slack failed)',
        message: input.text || 'Workflow error occurred',
        priority: 5,
        tags: ['rotating_light', 'warning']
      },
      slackError: input.error.message
    }
  };
}

return { json: { useFallback: false, success: true } };
